/**
 * Static capability flags for a provider.
 *
 * Each flag indicates whether the provider's models *generally* support that
 * feature.  For providers that aggregate many underlying models (e.g. Bedrock,
 * OpenRouter, vLLM) the flags reflect the superset of available model
 * capabilities — a flag being `true` means at least one model supports the
 * feature, not every model.
 *
 * All flags default to `false` so that newly added providers are safe.
 *
 * Access via the crate-level `capabilities` function:
 */
final class ProviderCapabilities
{
    public function __construct(
        /** @var bool The provider accepts image input in chat messages. */
        public readonly bool $vision,
        /** @var bool The provider supports extended-thinking / reasoning tokens. */
        public readonly bool $reasoning,
        /** @var bool The provider supports JSON-mode or `response_format` structured output. */
        public readonly bool $structuredOutput,
        /** @var bool The provider supports tool / function calling. */
        public readonly bool $functionCalling,
        /** @var bool The provider accepts audio as input. */
        public readonly bool $audioIn,
        /** @var bool The provider can generate audio / TTS output. */
        public readonly bool $audioOut,
        /** @var bool The provider accepts video as input. */
        public readonly bool $videoIn
    ) { }
}

