        /** @var ?string Base URL used as the default for this provider's HTTP client. */
        public readonly ?string $baseUrl = null,
        /** @var ?AuthConfig Authentication scheme metadata (auth type + env var holding the key). */
        public readonly ?AuthConfig $auth = null,
        /** @var ?array<string> Supported endpoint kinds (e.g. `chat`, `embeddings`). */
        public readonly ?array $endpoints = null,
        /** @var ?array<string> Model-name prefixes claimed by this provider (e.g. `["gpt-", "o1-"]`). */
        public readonly ?array $modelPrefixes = null,
        /**
         * Parameter key renaming for this provider.
         *
         * Each entry maps an OpenAI-spec field name (e.g. `"max_completion_tokens"`)
         * to the name this provider expects (e.g. `"max_tokens"`).  Applied
